class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type  # 'number', 'binop', 'unary'
        self.value = value  # for numbers
        self.op = op  # for operators
        self.left = left  # for binary operations
        self.right = right  # for binary operations
        self.operand = operand  # for unary operations


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty input")

    # Remove all whitespace
    expression = expression.replace(" ", "")

    # Tokenizer
    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isdigit() or expr[i] == ".":
                # Parse number
                start = i
                while i < len(expr) and (expr[i].isdigit() or expr[i] == "."):
                    i += 1
                tokens.append(("NUMBER", expr[start:i]))
            elif expr[i] in "+-*/()":
                tokens.append((expr[i], expr[i]))
                i += 1
            else:
                raise ValueError(f"Invalid token: {expr[i]}")
        return tokens

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Invalid expression")

    # Parser using recursive descent
    def parse_expression(index):
        return parse_add_sub(index)

    def parse_add_sub(index):
        left, index = parse_mul_div(index)

        while index < len(tokens) and tokens[index][0] in ["+", "-"]:
            op = tokens[index][0]
            index += 1
            right, index = parse_mul_div(index)
            left = ASTNode("binop", op=op, left=left, right=right)

        return left, index

    def parse_mul_div(index):
        left, index = parse_unary(index)

        while index < len(tokens) and tokens[index][0] in ["*", "/"]:
            op = tokens[index][0]
            index += 1
            right, index = parse_unary(index)
            left = ASTNode("binop", op=op, left=left, right=right)

        return left, index

    def parse_unary(index):
        if index < len(tokens) and tokens[index][0] == "-":
            index += 1
            operand, index = parse_factor(index)
            return ASTNode("unary", op="-", operand=operand), index
        else:
            return parse_factor(index)

    def parse_factor(index):
        if index >= len(tokens):
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[index]

        if token_type == "NUMBER":
            index += 1
            return ASTNode("number", value=float(token_value)), index
        elif token_type == "(":
            index += 1
            expr_node, index = parse_expression(index)
            if index >= len(tokens) or tokens[index][0] != ")":
                raise ValueError("Unmatched parenthesis")
            index += 1
            return expr_node, index
        else:
            raise ValueError(f"Unexpected token: {token_value}")

    # Parse the entire expression
    result, index = parse_expression(0)

    if index != len(tokens):
        raise ValueError("Invalid expression")

    return result


def evaluate(node):
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
    else:
        raise ValueError("Invalid AST node type")
